```c
#include <stdio.h>

int gcd(int a, int b) {
    while (b) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int cal(int i, int n) {
    int temp = 0;
    while (n > 0) {
        temp += n % i;
        n = n / i;
    }
    return temp;
}

int main() {
    int n;
    scanf("%d", &n);
    int sum = 0;
    for (int base = 2; base < n; base++) {
        sum += cal(base, n);
    }
    n -= 2;
    int common_divisor = gcd(sum, n);
    printf("%d/%d", sum / common_divisor, n / common_divisor);
    return 0;
}
